import{_ as l,o as e,c as t,a0 as o}from"./chunks/framework.CWk8AOcY.js";const b=JSON.parse('{"title":"什么是 Snapshot、冷启动与热启动","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/concepts/snapshot-hotstart.md","filePath":"zh/guide/concepts/snapshot-hotstart.md"}'),i={name:"zh/guide/concepts/snapshot-hotstart.md"};function r(h,a,n,s,p,d){return e(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="什么是-snapshot、冷启动与热启动" tabindex="-1">什么是 Snapshot、冷启动与热启动 <a class="header-anchor" href="#什么是-snapshot、冷启动与热启动" aria-label="Permalink to &quot;什么是 Snapshot、冷启动与热启动&quot;">​</a></h1><h2 id="一句话定义" tabindex="-1">一句话定义 <a class="header-anchor" href="#一句话定义" aria-label="Permalink to &quot;一句话定义&quot;">​</a></h2><p>CubeSandbox 的极速启动能力，本质上来自 <strong>对已经准备好的运行状态进行复用</strong>。</p><p>其中：</p><ul><li><strong>冷启动</strong> 是从更原始的起点把环境真正启动起来</li><li><strong>Snapshot</strong> 是把某个可复用状态固化下来</li><li><strong>热启动</strong> 是基于这个已固化状态快速恢复实例</li></ul><p>这三个概念不是并列功能，而是同一条性能链路上的三个环节。</p><h2 id="为什么-cubesandbox-必须依赖-snapshot" tabindex="-1">为什么 CubeSandbox 必须依赖 Snapshot <a class="header-anchor" href="#为什么-cubesandbox-必须依赖-snapshot" aria-label="Permalink to &quot;为什么 CubeSandbox 必须依赖 Snapshot&quot;">​</a></h2><p>如果每次创建 Sandbox 都要从最原始状态重新开始，平台将不可避免地付出这些成本：</p><ul><li>Guest 完整启动时间</li><li>语言运行时初始化时间</li><li>服务 ready 等待时间</li><li>文件与缓存准备时间</li><li>各种初始化过程带来的抖动</li></ul><p>这意味着即使底层隔离能力再强，交付速度仍然会受到传统启动链路的限制。</p><p>CubeSandbox 要解决的恰恰是：</p><blockquote><p><strong>如何在保留强隔离的前提下，把“实例就绪”这件事做得像缓存命中一样快。</strong></p></blockquote><p>Snapshot 就是这件事的关键。</p><h2 id="什么是冷启动" tabindex="-1">什么是冷启动 <a class="header-anchor" href="#什么是冷启动" aria-label="Permalink to &quot;什么是冷启动&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>冷启动指的是：</p><blockquote><p>从更原始、未预热的基础状态开始，把一个环境真正启动并走到可运行、可服务的过程。</p></blockquote><p>在 CubeSandbox 的语境里，冷启动通常发生在模板制作阶段，而不是每个用户请求阶段。</p><h3 id="为什么冷启动仍然重要" tabindex="-1">为什么冷启动仍然重要 <a class="header-anchor" href="#为什么冷启动仍然重要" aria-label="Permalink to &quot;为什么冷启动仍然重要&quot;">​</a></h3><p>很多人听到“热启动很快”，就误以为冷启动不重要了。</p><p>恰恰相反，冷启动非常重要，因为它负责完成那些无法凭空省略的准备工作：</p><ul><li>Guest 内核真正启动</li><li>用户态环境真正拉起</li><li>语言 / 服务运行时真正完成初始化</li><li>平台确认环境达到了可复用状态</li></ul><p>可以说：</p><p><strong>没有一次正确的冷启动，就不会有后续稳定的热启动。</strong></p><h3 id="冷启动的本质" tabindex="-1">冷启动的本质 <a class="header-anchor" href="#冷启动的本质" aria-label="Permalink to &quot;冷启动的本质&quot;">​</a></h3><p>冷启动不是为了用户即时体验，而是为了制造一个“值得复用”的状态基线。</p><p>所以在 CubeSandbox 里，冷启动更像是一次前置投资。</p><h2 id="什么是-snapshot" tabindex="-1">什么是 Snapshot <a class="header-anchor" href="#什么是-snapshot" aria-label="Permalink to &quot;什么是 Snapshot&quot;">​</a></h2><h3 id="定义-1" tabindex="-1">定义 <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Snapshot 是对某个运行状态的固化结果，使系统能够在后续快速恢复到这个状态，而不是重新从零初始化。</p><p>在 CubeSandbox 里，Snapshot 不是简单“存个文件”，而是高性能实例化模型的核心资产之一。</p><h3 id="snapshot-固化的是什么" tabindex="-1">Snapshot 固化的是什么 <a class="header-anchor" href="#snapshot-固化的是什么" aria-label="Permalink to &quot;Snapshot 固化的是什么&quot;">​</a></h3><p>从概念上讲，Snapshot 固化的是“已经准备好的系统状态”。</p><p>这通常意味着：</p><ul><li>Guest 已经完成一部分甚至大部分初始化</li><li>某些服务已经 ready</li><li>某些运行时已经被加载进内存</li><li>平台已经知道这是一个适合复制的时刻</li></ul><p>Snapshot 真正节省的，不是磁盘拷贝，而是 <strong>重复初始化成本</strong>。</p><h3 id="snapshot-不是-template-的全部-但通常是-template-的核心能力之一" tabindex="-1">Snapshot 不是 Template 的全部，但通常是 Template 的核心能力之一 <a class="header-anchor" href="#snapshot-不是-template-的全部-但通常是-template-的核心能力之一" aria-label="Permalink to &quot;Snapshot 不是 Template 的全部，但通常是 Template 的核心能力之一&quot;">​</a></h3><p>Template 是发布对象；Snapshot 是状态复用机制。</p><p>可以把两者理解为：</p><ul><li>Template 决定“这个环境是什么”</li><li>Snapshot 决定“这个环境为什么能被快速交付”</li></ul><h2 id="什么是热启动" tabindex="-1">什么是热启动 <a class="header-anchor" href="#什么是热启动" aria-label="Permalink to &quot;什么是热启动&quot;">​</a></h2><h3 id="定义-2" tabindex="-1">定义 <a class="header-anchor" href="#定义-2" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>热启动指的是：</p><blockquote><p>基于已经准备好的模板与快照状态，快速恢复并交付一个新的 Sandbox，而不是从最原始状态重新完成整套启动流程。</p></blockquote><h3 id="为什么热启动不是-偷懒版启动" tabindex="-1">为什么热启动不是“偷懒版启动” <a class="header-anchor" href="#为什么热启动不是-偷懒版启动" aria-label="Permalink to &quot;为什么热启动不是“偷懒版启动”&quot;">​</a></h3><p>热启动并不是少做了工作，而是把工作做在了更合适的时机：</p><ul><li>应该复用的部分提前做好并冻结</li><li>不可共享的实例级状态在实例化时再补上</li><li>通过分层组织，让“共享基础”与“实例差异”解耦</li></ul><p>所以热启动的本质不是简化逻辑，而是重排成本结构。</p><h2 id="三者的关系-一条连续链路" tabindex="-1">三者的关系：一条连续链路 <a class="header-anchor" href="#三者的关系-一条连续链路" aria-label="Permalink to &quot;三者的关系：一条连续链路&quot;">​</a></h2><p>最容易记住的关系是：</p><ol><li><strong>冷启动制造可复用状态</strong></li><li><strong>Snapshot 固化可复用状态</strong></li><li><strong>热启动恢复并交付这个状态</strong></li></ol><p>如果只理解其中一个，而忽略另外两个，都会得出错误结论：</p><ul><li>只讲冷启动，会觉得系统和普通 VM 没区别</li><li>只讲 Snapshot，会看不出它为何值得制作</li><li>只讲热启动，会误以为速度来自“神秘优化”</li></ul><p>实际上它们是一条完整的因果链。</p><h2 id="为什么-cubesandbox-能做到-强隔离-快交付" tabindex="-1">为什么 CubeSandbox 能做到“强隔离 + 快交付” <a class="header-anchor" href="#为什么-cubesandbox-能做到-强隔离-快交付" aria-label="Permalink to &quot;为什么 CubeSandbox 能做到“强隔离 + 快交付”&quot;">​</a></h2><p>很多系统只能在两者之间做取舍：</p><ul><li>要快，就用共享内核容器</li><li>要隔离，就接受传统 VM 启动成本</li></ul><p>CubeSandbox 的设计目标不是在两者之间二选一，而是通过模板化和快照化，把“强隔离实例的初始化成本”尽量前移和摊薄。</p><p>换句话说，CubeSandbox 的关键创新不只是虚拟化本身，而是：</p><blockquote><p><strong>把虚拟化实例的启动过程产品化、模板化、快照化。</strong></p></blockquote><p>这才使得强隔离与低时延能够同时成立。</p><h2 id="热启动到底快在什么地方" tabindex="-1">热启动到底快在什么地方 <a class="header-anchor" href="#热启动到底快在什么地方" aria-label="Permalink to &quot;热启动到底快在什么地方&quot;">​</a></h2><p>热启动快，不是因为 CPU 更快，也不主要是因为 I/O 更强，而是因为它少走了许多重复路径。</p><h3 id="_1-少走了-guest-从零引导路径" tabindex="-1">1. 少走了 Guest 从零引导路径 <a class="header-anchor" href="#_1-少走了-guest-从零引导路径" aria-label="Permalink to &quot;1. 少走了 Guest 从零引导路径&quot;">​</a></h3><p>传统 VM 的完整引导链路非常长。</p><p>热启动通过复用已经准备好的状态，绕开了很多启动早期阶段。</p><h3 id="_2-少走了运行时初始化路径" tabindex="-1">2. 少走了运行时初始化路径 <a class="header-anchor" href="#_2-少走了运行时初始化路径" aria-label="Permalink to &quot;2. 少走了运行时初始化路径&quot;">​</a></h3><p>例如语言运行时、常驻服务、依赖加载等，往往都是高频重复成本。</p><h3 id="_3-少走了平台-ready-判定等待" tabindex="-1">3. 少走了平台 ready 判定等待 <a class="header-anchor" href="#_3-少走了平台-ready-判定等待" aria-label="Permalink to &quot;3. 少走了平台 ready 判定等待&quot;">​</a></h3><p>如果模板制作时已经把环境推到了稳定可用状态，那么实例创建时不需要每次重新等待整套准备过程。</p><h2 id="snapshot-带来的不只是-快" tabindex="-1">Snapshot 带来的不只是“快” <a class="header-anchor" href="#snapshot-带来的不只是-快" aria-label="Permalink to &quot;Snapshot 带来的不只是“快”&quot;">​</a></h2><h3 id="_1-更稳定的交付时延" tabindex="-1">1. 更稳定的交付时延 <a class="header-anchor" href="#_1-更稳定的交付时延" aria-label="Permalink to &quot;1. 更稳定的交付时延&quot;">​</a></h3><p>如果每次都从零初始化，时延波动会非常大。</p><p>基于 Snapshot 恢复，系统更容易获得稳定、可预测的交付时间。</p><h3 id="_2-更高的并发扩展能力" tabindex="-1">2. 更高的并发扩展能力 <a class="header-anchor" href="#_2-更高的并发扩展能力" aria-label="Permalink to &quot;2. 更高的并发扩展能力&quot;">​</a></h3><p>在高并发场景下，重复做昂贵初始化会迅速放大资源压力。</p><p>Snapshot 让系统把很多成本集中在模板构建阶段，从而改善在线请求路径的压力结构。</p><h3 id="_3-更强的一致性" tabindex="-1">3. 更强的一致性 <a class="header-anchor" href="#_3-更强的一致性" aria-label="Permalink to &quot;3. 更强的一致性&quot;">​</a></h3><p>相同 Template 对应的 Snapshot 能让一批实例从同一准备状态出发，这对可复现性和问题排查非常重要。</p><h2 id="为什么-快照回滚-是更进一步的概念" tabindex="-1">为什么“快照回滚”是更进一步的概念 <a class="header-anchor" href="#为什么-快照回滚-是更进一步的概念" aria-label="Permalink to &quot;为什么“快照回滚”是更进一步的概念&quot;">​</a></h2><p>一旦理解了“模板级快照用于快速创建实例”，就会发现更进一步的能力自然浮现出来：</p><ul><li>在运行中的某个时间点保存状态</li><li>需要时回滚到那个时间点</li><li>从某个历史状态快速分叉多个新环境</li></ul><p>这就是为什么快照能力不仅影响启动速度，还影响未来的：</p><ul><li>并行探索</li><li>环境回放</li><li>分叉执行</li><li>调试与测试复现</li></ul><p>也就是说，Snapshot 不是单点性能技巧，而是一种非常基础的状态组织能力。</p><h2 id="什么状态能共享-什么状态不能共享" tabindex="-1">什么状态能共享，什么状态不能共享 <a class="header-anchor" href="#什么状态能共享-什么状态不能共享" aria-label="Permalink to &quot;什么状态能共享，什么状态不能共享&quot;">​</a></h2><p>这是理解 Snapshot 时必须保持清醒的一点。</p><h3 id="可共享的是模板级准备成果" tabindex="-1">可共享的是模板级准备成果 <a class="header-anchor" href="#可共享的是模板级准备成果" aria-label="Permalink to &quot;可共享的是模板级准备成果&quot;">​</a></h3><p>例如：</p><ul><li>已初始化好的基础环境</li><li>已就绪的常见运行时</li><li>可作为母版的内存 / 磁盘基线</li></ul><h3 id="不可直接共享的是实例级差异状态" tabindex="-1">不可直接共享的是实例级差异状态 <a class="header-anchor" href="#不可直接共享的是实例级差异状态" aria-label="Permalink to &quot;不可直接共享的是实例级差异状态&quot;">​</a></h3><p>例如：</p><ul><li>当前用户代码执行结果</li><li>当前实例创建后的临时文件</li><li>实例独有网络连接</li><li>实例运行中的实时修改</li></ul><p>所以 Snapshot 让系统“共享基础”，而不是“共享一切”。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><h3 id="误解一-有快照就不需要模板" tabindex="-1">误解一：有快照就不需要模板 <a class="header-anchor" href="#误解一-有快照就不需要模板" aria-label="Permalink to &quot;误解一：有快照就不需要模板&quot;">​</a></h3><p>不对。</p><p>快照是机制，模板是平台对象。快照可以是模板的一部分，但不能替代模板的治理和发布语义。</p><h3 id="误解二-热启动等于完全没有启动成本" tabindex="-1">误解二：热启动等于完全没有启动成本 <a class="header-anchor" href="#误解二-热启动等于完全没有启动成本" aria-label="Permalink to &quot;误解二：热启动等于完全没有启动成本&quot;">​</a></h3><p>不对。</p><p>热启动只是显著降低成本，而不是完全消灭成本。实例仍然需要：</p><ul><li>获得自己的实例标识</li><li>建立自己的网络与路由</li><li>挂接自己的写时状态</li><li>完成必要的运行时接线</li></ul><h3 id="误解三-冷启动就是失败方案-热启动才是正确方案" tabindex="-1">误解三：冷启动就是失败方案，热启动才是正确方案 <a class="header-anchor" href="#误解三-冷启动就是失败方案-热启动才是正确方案" aria-label="Permalink to &quot;误解三：冷启动就是失败方案，热启动才是正确方案&quot;">​</a></h3><p>不对。</p><p>冷启动和热启动不是好坏对立，而是分工不同：</p><ul><li>冷启动负责准备与生产</li><li>热启动负责复用与交付</li></ul><h2 id="平台设计者最该关心什么" tabindex="-1">平台设计者最该关心什么 <a class="header-anchor" href="#平台设计者最该关心什么" aria-label="Permalink to &quot;平台设计者最该关心什么&quot;">​</a></h2><p>如果你站在平台或架构视角看，这个概念族最重要的不是“快照实现细节”，而是四个判断：</p><ol><li><strong>系统是否把昂贵初始化成功前移。</strong></li><li><strong>模板与快照的边界是否清晰。</strong></li><li><strong>共享状态与实例差异状态是否严格分层。</strong></li><li><strong>热启动性能是否建立在可治理、可重复的模板流程上。</strong></li></ol><h2 id="和其它概念的关系" tabindex="-1">和其它概念的关系 <a class="header-anchor" href="#和其它概念的关系" aria-label="Permalink to &quot;和其它概念的关系&quot;">​</a></h2><ul><li>和 <a href="./template.html">Template</a> 的关系：Template 是母版对象，Snapshot 是其关键能力之一</li><li>和 <a href="./sandbox.html">Sandbox</a> 的关系：Sandbox 是最终被交付的实例</li><li>和 <a href="./microvm-runtime-guest.html">MicroVM / Runtime / Guest</a> 的关系：快照复用发生在这些运行时层之上</li><li>和 <a href="./filesystem-image-writable-layer.html">文件系统、镜像与可写层</a> 的关系：共享基础与实例差异要靠分层状态组织实现</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>理解了实例为什么能快，下一步就该理解：</p><p><strong>这些实例最终是如何分布在机器上、被谁管理、被谁调度的？</strong></p><p>这就进入集群抽象： <a href="./node-cluster-scheduling.html">什么是 Node、集群与调度</a>。</p>',115)])])}const c=l(i,[["render",r]]);export{b as __pageData,c as default};
